import { useContext, useEffect, useRef, useState } from "react"
import styles from './DashboardLevel4.module.css'
import { DashboardV4PressureEntity } from "../../entities/DashboardEntity"
import { BASE_URL } from "../../constants"
import { format, formatDate } from "date-fns"
import AppContext from "../../context"
import filterUtils from "../../utils/filter-utils"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { FaAngleDoubleLeft, FaAngleDoubleRight, FaAngleLeft, FaAngleRight, FaArrowCircleLeft, FaChartLine, FaSortDown, FaSortUp, FaTable } from "react-icons/fa"
import { DashboardService } from "../../services/dashboard"
import { useLocation, useParams } from "react-router-dom"
import TableObserved from "../../components/Observer/observer"
import { GrLineChart } from "react-icons/gr"
import { TbTable } from "react-icons/tb"

// ========================================= CHART IMPORT =========================================  //
import {
    Chart as ChartJS,
    LineElement,
    PointElement,
    LinearScale,
    Title,
    CategoryScale,
    Tooltip,
    Legend,
    ChartData,
    ChartOptions,
    defaults
} from 'chart.js'

import { Plugin } from 'chart.js'
import { Line } from 'react-chartjs-2'
import ExcelUtils from "../../utils/excel"

ChartJS.register(
    LineElement,
    PointElement,
    LinearScale,
    Title,
    CategoryScale,
    Tooltip,
    Legend
)

defaults.maintainAspectRatio = false
defaults.responsive = true
// ========================================= CHART IMPORT =========================================  //


interface PressurePageProps {
    realtime: boolean
    setRealtime: (value: boolean) => void
    refresh: number
    start_date: Date
    end_date: Date
    setHandleGenerateExcel: (fn: (() => void) | null) => void
}


const PressurePage: React.FC<PressurePageProps> = ({ realtime, setRealtime, refresh, start_date, end_date, setHandleGenerateExcel }) => {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //


    const { machineId } = useParams()

    const CHART_COLORS = {
        chartLine: '#fb8500',
        graphicGood: 'rgba(41, 191, 18, 0.21)',
        graphicWarn: 'rgba(244, 188, 20, 0.28)',
        graphicAlarm: 'rgba(213, 14, 81, 0.2)',
    }

    const [activeHourIndex, setActiveHourIndex] = useState(new Date())
    const [isAuto, setIsAuto] = useState(true)
    const [viewMode, setViewMode] = useState<'chart' | 'table' | 'table-ool'>('chart')
    const [sortedCols, setSortedCols] = useState<keyof DashboardV4PressureEntity | null>(null)
    const [sortedColsType, setSortedColsType] = useState<"ascending" | "descending">("ascending")


    // ========================================= STATE PRESSURE BY DATE =========================================  //
    const [tableData, setTableData] = useState<DashboardV4PressureEntity[]>([])
    const [tableDataCache, setTableDataCache] = useState<DashboardV4PressureEntity[]>([])
    const mappedDataRef = useRef<{ [key: string]: DashboardV4PressureEntity[] }>({})

    const [tableDataFilter, setTableDataFilter] = useState<{ [key: string]: string }>({})

    const [chartData, setChartData] = useState<ChartData<'line'>>({ labels: [], datasets: [] })
    const [chartOptions, setChartOptions] = useState<ChartOptions<'line'>>({})

    const firstData = useRef<DashboardV4PressureEntity | null>(null)
    // ========================================= STATE PRESSURE BY DATE =========================================  //


    // ========================================= STATE PRESSURE REALTIME =========================================  //
    let pressureSocket: WebSocket | null = null
    let reconnectPressure = true

    const [tableDataRealtime, setTableDataRealtime] = useState<DashboardV4PressureEntity[]>([])
    const [tableDataRealtimeCache, setTableDataRealtimeCache] = useState<DashboardV4PressureEntity[]>([])

    const [tableDataRealtimeFilter, setTableDataRealtimeFilter] = useState<{ [key: string]: string }>({})

    const [chartDataRealtime, setChartDataRealtime] = useState<ChartData<'line'>>({ labels: [], datasets: [], })
    const [chartOptionsRealtime, setChartOptionsRealtime] = useState<ChartOptions<'line'>>({})

    const firstDataRealtime = useRef<DashboardV4PressureEntity | null>(null)
    // ========================================= STATE PRESSURE REALTIME =========================================  //


    function splitDataBy10Minutes(data: DashboardV4PressureEntity[]) {
        const map: { [key: string]: DashboardV4PressureEntity[] } = {}

        data.toReversed().forEach(item => {
            const date = new Date(item.timestamp)
            const rounded = new Date(date)
            rounded.setMinutes(Math.floor(date.getMinutes() / 10) * 10)
            rounded.setSeconds(0)
            rounded.setMilliseconds(0)

            const key = format(rounded, "yyyy-MM-dd HH:mm")

            if (map[key] == undefined) {
                map[key] = []
            } else {
                map[key].push(item)
            }
        })

        return map
    }


    // ========================================= FUNCTIONS PRESSURE BY DATE =========================================  //
    const statusArea: Plugin<'line'> = {
        id: 'statusArea',
        beforeDatasetsDraw(chart) {
            const pressureData = firstData.current

            const { ctx, chartArea, scales } = chart
            if (
                !chartArea ||
                !scales.x ||
                !scales.y ||
                pressureData?.pressure_max_alarm == null ||
                pressureData?.pressure_min_alarm == null ||
                pressureData?.pressure_max_warn == null ||
                pressureData?.pressure_min_warn == null
            ) return

            ctx.save()

            // --- Area Alarm (Merah) ---
            const startMinAlarm = scales.y.min
            const endMinAlarm = pressureData?.pressure_min_alarm ?? 0

            const startMinAlarmPixel = scales.y.getPixelForValue(startMinAlarm)
            const endMinAlarmPixel = scales.y.getPixelForValue(endMinAlarm)

            ctx.fillStyle = CHART_COLORS.graphicAlarm
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinAlarmPixel, endMinAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinAlarmPixel - endMinAlarmPixel)
            )

            const startMaxAlarm = pressureData?.pressure_max_alarm ?? 0
            const endMaxAlarm = scales.y.max

            const startMaxAlarmPixel = scales.y.getPixelForValue(startMaxAlarm)
            const endMaxAlarmPixel = scales.y.getPixelForValue(endMaxAlarm)

            ctx.fillRect(
                chartArea.left,
                Math.min(startMaxAlarmPixel, endMaxAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMaxAlarmPixel - endMaxAlarmPixel)
            )

            // --- Area Normal (Green) ---
            const startNormalArea = pressureData?.pressure_min_warn ?? 0
            const endNormalArea = pressureData?.pressure_max_warn ?? 0

            const startNormalAreaPixel = scales.y.getPixelForValue(startNormalArea)
            const endNormalAreaPixel = scales.y.getPixelForValue(endNormalArea)

            ctx.fillStyle = CHART_COLORS.graphicGood
            ctx.fillRect(
                chartArea.left,
                Math.min(startNormalAreaPixel, endNormalAreaPixel),
                chartArea.right - chartArea.left,
                Math.abs(startNormalAreaPixel - endNormalAreaPixel)
            )

            // --- Area Warn (Kuning) ---
            const startMinWarn = pressureData?.pressure_min_alarm ?? 0
            const endMinWarn = pressureData?.pressure_min_warn ?? 0

            const startMinWarnPixel = scales.y.getPixelForValue(startMinWarn)
            const endMinWarnPixel = scales.y.getPixelForValue(endMinWarn)

            ctx.fillStyle = CHART_COLORS.graphicWarn
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinWarnPixel, endMinWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinWarnPixel - endMinWarnPixel)
            )

            const startMaxWarn = pressureData?.pressure_max_warn ?? 0
            const endMaxWarn = pressureData?.pressure_max_alarm ?? 0

            const startMaxWarnPixel = scales.y.getPixelForValue(startMaxWarn)
            const endMaxWarnPixel = scales.y.getPixelForValue(endMaxWarn)

            ctx.fillRect(
                chartArea.left,
                Math.min(startMaxWarnPixel, endMaxWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMaxWarnPixel - endMaxWarnPixel)
            )

            ctx.restore()
        }
    }
    const updateChart = (mapData: { [key: string]: DashboardV4PressureEntity[] }, activeHourIndex: Date) => {
        // Get Data by activeHourIndex
        const flooredMinutes = `${Math.floor(activeHourIndex.getMinutes() / 10)}0`
        const key = format(activeHourIndex, "yyyy-MM-dd HH:" + `${flooredMinutes}`)

        const groupData = mapData[key] ?? []

        if (!groupData) {
            return
        }

        // Get Labels & Data
        const newLabels = groupData.map(msg => format(msg.timestamp, "HH:mm:ss"))
        const newData = groupData.map(msg => msg.pressure)

        // Get Area Warn, Alarm & Good
        const reversedData = groupData.toReversed()
        firstData.current = reversedData[0]

        // Calculate min & max y
        const dataMin = Math.min(...newData)
        const dataMax = Math.max(...newData)
        const range = dataMax - dataMin || 1
        const padding = 0.2

        const customMin = dataMin - range * padding
        const customMax = dataMax + range * padding

        setChartData({
            labels: newLabels,
            datasets: [
                {
                    label: "Pressure Sensor",
                    data: newData,
                    borderColor: CHART_COLORS.chartLine,
                    pointBackgroundColor: CHART_COLORS.chartLine,
                    pointBorderColor: '#ffffff',
                    pointHoverBackgroundColor: '#ffffff',
                    pointHoverBorderColor: CHART_COLORS.chartLine,

                    borderWidth: 4,
                    pointRadius: 0,
                },
            ],
        })

        setChartOptions({
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 800,
                easing: 'easeInOutCubic',
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        color: '#fbeecc',
                        font: {
                            size: 14,
                            weight: 500,
                            family: "'Inter', 'Segoe UI', sans-serif",
                        },
                        usePointStyle: true,
                        pointStyle: 'rectRounded',
                    },
                },
                tooltip: {
                    backgroundColor: '#1f2937',
                    titleColor: '#f8fafc',
                    bodyColor: '#cbd5e1',
                    padding: 12,
                    borderColor: '#0077b6',
                    borderWidth: 1,
                    cornerRadius: 8,
                    titleFont: {
                        family: "'Inter', sans-serif",
                        size: 14,
                        weight: 600,
                    },
                    bodyFont: {
                        family: "'Inter', sans-serif",
                        size: 13,
                    },
                },
            },
            scales: {
                x: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        maxRotation: 45,
                        minRotation: 0,
                    },
                },
                y: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        padding: 8,
                    },
                    min: customMin,
                    max: customMax,
                },
            },
            layout: {
                padding: {
                    top: 10,
                    bottom: 10,
                    left: 10,
                    right: 10,
                },
            },
            elements: {
                line: {
                    borderJoinStyle: 'round',
                },
                point: {
                    pointStyle: 'circle',
                },
            },
        })
    }

    const handleFilterAndSort = () => {
        const table_filtered = tableDataCache.filter((row) => {
            return filterUtils.FilterTable(row, tableDataFilter)
        }).sort((a, b) => {
            if (!sortedCols) { return 0 }
            if (sortedColsType == "ascending") {
                return filterUtils.SortingTable(a, b, sortedCols)
            } else {
                return filterUtils.SortingTable(b, a, sortedCols)
            }
        })
        setTableData(table_filtered)
    }
    const filterTable = (column: keyof DashboardV4PressureEntity, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", width: "150px" }} type="text" value={tableDataFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }
    const headerTable = (column: keyof DashboardV4PressureEntity, columnName?: string) => {
        return <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
            onClick={() => {
                setSortedCols(column)
                if (sortedColsType === "ascending") {
                    setSortedColsType("descending")
                } else {
                    setSortedColsType("ascending")
                }
            }}
        >
            <div>{columnName ?? column}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                <FaSortUp style={{ color: ((sortedCols == column && sortedColsType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                <FaSortDown style={{ color: ((sortedCols == column && sortedColsType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
            </div>
        </div>
    }

    const generateData = async (withLoading: boolean) => {
        if (withLoading) {
            contextShowLoadingFunc(true)
        }

        try {
            const resp = await DashboardService.GetDashboardLevel4Pressure(
                Number(machineId),
                formatDate(start_date, 'yyyy-MM-dd'),
                formatDate(end_date, 'yyyy-MM-dd')
            )
            setTableData(resp)
            setTableDataCache(resp)

            const map = splitDataBy10Minutes(resp)
            mappedDataRef.current = map

            const keys = Object.keys(map)
            if (keys.length > 0) {
                const newDate = new Date(keys[keys.length - 1])
                setActiveHourIndex(newDate)
                updateChart(mappedDataRef.current, newDate)
            } else {
                updateChart(mappedDataRef.current, activeHourIndex)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({
                message: error instanceof Error ? error.message : error.toString(),
                level: 3
            }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }
    const pressureDataRows = (index: number, row: DashboardV4PressureEntity) => {
        let valueColor = 'black'
        let valueWeight = '400'

        const { pressure, pressure_max_warn, pressure_min_warn, pressure_max_alarm, pressure_min_alarm } = row

        if (
            pressure_max_warn !== undefined &&
            pressure_min_warn !== undefined &&
            pressure < pressure_max_warn &&
            pressure > pressure_min_warn
        ) {
            valueColor = 'green'
            valueWeight = 'bold'
        }

        if (
            pressure_max_warn !== undefined &&
            pressure_min_warn !== undefined &&
            (pressure >= pressure_max_warn || pressure <= pressure_min_warn)
        ) {
            valueColor = 'orange'
            valueWeight = 'bold'
        }

        if (
            pressure_max_alarm !== undefined &&
            pressure_min_alarm !== undefined &&
            (pressure >= pressure_max_alarm || pressure <= pressure_min_alarm)
        ) {
            valueColor = 'red'
            valueWeight = 'bold'
        }

        return <>
            <td>{index + 1}</td>
            <td>{format(row.timestamp, `yyyy-MM-dd HH:mm:ss`)}</td>
            <td>{row.pressure}</td>
            <td>{row.pressure_max_alarm}</td>
            <td>{row.pressure_max_warn}</td>
            <td>{row.pressure_min_alarm}</td>
            <td>{row.pressure_min_warn}</td>
        </>
    }

    useEffect(() => {
        handleFilterAndSort()
    }, [tableDataFilter, sortedCols, sortedColsType])

    useEffect(() => {
        // no loading on first open
        generateData(refresh != 0)
    }, [refresh])
    // ========================================= FUNCTIONS PRESSURE BY DATE =========================================  //


    // ========================================= FUNCTIONS PRESSURE REALTIME =========================================  //
    const statusAreaRealtime: Plugin<'line'> = {
        id: 'statusAreaRealtime',
        beforeDatasetsDraw(chart) {
            const pressureData = firstDataRealtime.current

            const { ctx, chartArea, scales } = chart
            if (!chartArea || !scales.x || !scales.y) {
                return
            }

            if (!pressureData ||
                (pressureData.pressure_min_warn === 0 || pressureData.pressure_min_warn == null) &&
                (pressureData.pressure_max_warn === 0 || pressureData.pressure_max_warn == null) &&
                (pressureData.pressure_min_alarm === 0 || pressureData.pressure_min_alarm == null) &&
                (pressureData.pressure_max_alarm === 0 || pressureData.pressure_max_alarm == null)
            ) {
                return
            }

            ctx.save()

            // --- Area MIN Alarm (Merah) ---
            const startMinAlarm = scales.y.min
            const endMinAlarm = pressureData?.pressure_min_alarm ?? 0

            const startMinAlarmPixel = scales.y.getPixelForValue(startMinAlarm)
            const endMinAlarmPixel = scales.y.getPixelForValue(endMinAlarm)

            ctx.fillStyle = CHART_COLORS.graphicAlarm
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinAlarmPixel, endMinAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinAlarmPixel - endMinAlarmPixel)
            )

            // --- Area MAX Alarm (Merah) ---
            const startMaxAlarm = pressureData?.pressure_max_alarm ?? 0
            const endMaxAlarm = scales.y.max

            const startMaxAlarmPixel = scales.y.getPixelForValue(startMaxAlarm)
            const endMaxAlarmPixel = scales.y.getPixelForValue(endMaxAlarm)

            ctx.fillRect(
                chartArea.left,
                Math.min(startMaxAlarmPixel, endMaxAlarmPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMaxAlarmPixel - endMaxAlarmPixel)
            )

            // --- Area Normal (Green) ---
            const startNormalArea = pressureData?.pressure_min_warn ?? 0
            const endNormalArea = pressureData?.pressure_max_warn ?? 0

            const startNormalAreaPixel = scales.y.getPixelForValue(startNormalArea)
            const endNormalAreaPixel = scales.y.getPixelForValue(endNormalArea)

            ctx.fillStyle = CHART_COLORS.graphicGood
            ctx.fillRect(
                chartArea.left,
                Math.min(startNormalAreaPixel, endNormalAreaPixel),
                chartArea.right - chartArea.left,
                Math.abs(startNormalAreaPixel - endNormalAreaPixel)
            )

            // --- Area MIN Warn (Kuning) ---
            const startMinWarn = pressureData?.pressure_min_alarm ?? 0
            const endMinWarn = pressureData?.pressure_min_warn ?? 0

            const startMinWarnPixel = scales.y.getPixelForValue(startMinWarn)
            const endMinWarnPixel = scales.y.getPixelForValue(endMinWarn)

            ctx.fillStyle = CHART_COLORS.graphicWarn
            ctx.fillRect(
                chartArea.left,
                Math.min(startMinWarnPixel, endMinWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMinWarnPixel - endMinWarnPixel)
            )

            // --- Area MAX Warn (Kuning) ---
            const startMaxWarn = pressureData?.pressure_max_warn ?? 0
            const endMaxWarn = pressureData?.pressure_max_alarm ?? 0

            const startMaxWarnPixel = scales.y.getPixelForValue(startMaxWarn)
            const endMaxWarnPixel = scales.y.getPixelForValue(endMaxWarn)

            ctx.fillRect(
                chartArea.left,
                Math.min(startMaxWarnPixel, endMaxWarnPixel),
                chartArea.right - chartArea.left,
                Math.abs(startMaxWarnPixel - endMaxWarnPixel)
            )

            ctx.restore()
        }
    }
    const updateChartRealtime = (mapData: { [key: string]: DashboardV4PressureEntity[] }, activeHourIndex: Date) => {
        // Get Data by activeHourIndex
        const flooredMinutes = `${Math.floor(activeHourIndex.getMinutes() / 10)}0`
        const key = format(activeHourIndex, "yyyy-MM-dd HH:" + `${flooredMinutes}`)

        const groupData = mapData[key] ?? []

        if (!groupData) {
            return
        }

        // Get Labels & Data
        const newLabels = groupData.map(msg => format(msg.timestamp, "HH:mm:ss"))
        const newData = groupData.map(msg => msg.pressure)

        // Get Area Warn, Alarm & Good
        const firstData = groupData[0]
        firstDataRealtime.current = firstData

        // Calculate min & max y
        const dataMin = Math.min(...newData)
        const dataMax = Math.max(...newData)
        const range = dataMax - dataMin || 1
        const padding = 0.2

        const customMin = dataMin - range * padding
        const customMax = dataMax + range * padding


        setChartDataRealtime({
            labels: newLabels,
            datasets: [
                {
                    label: "Pressure Sensor",
                    data: newData,
                    borderColor: CHART_COLORS.chartLine,
                    pointBackgroundColor: CHART_COLORS.chartLine,
                    pointBorderColor: '#ffffff',
                    pointHoverBackgroundColor: '#ffffff',
                    pointHoverBorderColor: CHART_COLORS.chartLine,

                    borderWidth: 4,
                    pointRadius: 0
                },
            ],
        })

        setChartOptionsRealtime({
            responsive: true,
            maintainAspectRatio: false,
            animation: {
                duration: 800,
                easing: 'easeInOutCubic',
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        color: '#fbeecc',
                        font: {
                            size: 14,
                            weight: 500,
                            family: "'Inter', 'Segoe UI', sans-serif",
                        },
                        usePointStyle: true,
                        pointStyle: 'rectRounded',
                    },
                },
                tooltip: {
                    backgroundColor: '#1f2937',
                    titleColor: '#f8fafc',
                    bodyColor: '#cbd5e1',
                    padding: 12,
                    borderColor: '#0077b6',
                    borderWidth: 1,
                    cornerRadius: 8,
                    titleFont: {
                        family: "'Inter', sans-serif",
                        size: 14,
                        weight: 600,
                    },
                    bodyFont: {
                        family: "'Inter', sans-serif",
                        size: 13,
                    },
                },
            },
            scales: {
                x: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        maxRotation: 45,
                        minRotation: 0,
                    },
                },
                y: {
                    grid: {
                        color: '#0d2b35',
                    },
                    ticks: {
                        color: '#fbeecc',
                        font: {
                            size: 12,
                            family: "'Inter', sans-serif",
                        },
                        padding: 8,
                    },
                    min: customMin,
                    max: customMax,
                },
            },
            layout: {
                padding: {
                    top: 10,
                    bottom: 10,
                    left: 10,
                    right: 10,
                },
            },
            elements: {
                line: {
                    borderJoinStyle: 'round',
                },
                point: {
                    pointStyle: 'circle',
                },
            },
        })
    }

    const handleFilterAndSortRealtime = () => {
        const table_filtered = tableDataRealtimeCache.filter((row) => {
            return filterUtils.FilterTable(row, tableDataRealtimeFilter)
        }).sort((a, b) => {
            if (!sortedCols) { return 0 }
            if (sortedColsType == "ascending") {
                return filterUtils.SortingTable(a, b, sortedCols)
            } else {
                return filterUtils.SortingTable(b, a, sortedCols)
            }
        })
        setTableDataRealtime(table_filtered)
    }
    const filterTableRealtime = (column: keyof DashboardV4PressureEntity, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", width: "150px" }} type="text" value={tableDataRealtimeFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataRealtimeFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }
    const headerTableRealtime = (column: keyof DashboardV4PressureEntity, columnName?: string) => {
        return <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }}
            onClick={() => {
                setSortedCols(column)
                if (sortedColsType === "ascending") {
                    setSortedColsType("descending")
                } else {
                    setSortedColsType("ascending")
                }
            }}
        >
            <div>{columnName ?? column}</div>
            <div style={{ display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center" }}>
                <FaSortUp style={{ color: ((sortedCols == column && sortedColsType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                <FaSortDown style={{ color: ((sortedCols == column && sortedColsType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
            </div>
        </div>
    }

    const connectPressure = () => {
        if (!reconnectPressure) {
            console.log("canceled")
            return
        }

        return new Promise((resolve, reject) => {
            try {
                pressureSocket = new WebSocket(`${BASE_URL}/ws/realtime/pressure`)

                pressureSocket.onmessage = (event: MessageEvent) => {
                    try {
                        const response = JSON.parse(event.data)
                        setTableDataRealtime(response.data)
                        setTableDataRealtimeCache(response.data)
                    } catch (error: any) {
                        console.log("Invalid response: ", error.message)
                    }
                }

                pressureSocket.onerror = (err) => {
                    console.error("WebSocket error:", err)
                    pressureSocket?.close()
                }

                pressureSocket.onclose = async () => {
                    console.log("pressureSocket closed.")
                    console.log("Try reconnecting...")
                    try {
                        await connectPressure()
                    } catch (error) {
                        console.log("Failed to reconnect")
                    }
                }

                pressureSocket.onopen = () => {
                    console.log("pressureSocket connected")
                    const machineIdPayload = {
                        type: "subscribe",
                        machine_id: machineId,
                    }
                    pressureSocket?.send(JSON.stringify(machineIdPayload))
                    resolve(true)
                }
            } catch (error) {
                console.log("Error reconnect: ", error)
                reject(false)
            }
        })
    }

    useEffect(() => {
        if (pressureSocket == null || pressureSocket.readyState == WebSocket.CLOSED) {
            console.log("Connecting ws pressure...")
            connectPressure()
        }
        return () => {
            if (pressureSocket != null) {
                console.log("Disconnecting ws pressure...")
                pressureSocket.close()
            }
            reconnectPressure = false
        }
    }, [pressureSocket])
    useEffect(() => {
        handleFilterAndSortRealtime()
    }, [tableDataRealtimeFilter, sortedCols, sortedColsType])
    // ========================================= FUNCTIONS PRESSURE REALTIME =========================================  //

    // Auto mode
    useEffect(() => {
        if (!realtime) return
        if (!isAuto) return

        const map = splitDataBy10Minutes(tableDataRealtime)
        const newDate = new Date()
        newDate.setMinutes(Math.floor(newDate.getMinutes() / 10) * 10)

        setActiveHourIndex(newDate)
        updateChartRealtime(map, newDate)
    }, [isAuto, realtime, tableDataRealtime])

    // Manual mode
    useEffect(() => {
        if (!realtime) return
        if (isAuto) return

        const map = splitDataBy10Minutes(tableDataRealtime)
        updateChartRealtime(map, activeHourIndex)
    }, [isAuto, realtime, tableDataRealtime, activeHourIndex])

    const handleChangeActiveHourIndex = (amount: number, unit: 'hours' | 'minutes') => {
        setIsAuto(false)
        const newDate = new Date(activeHourIndex)
        const flooredMinutes = Math.floor(newDate.getMinutes() / 10) * 10
        if (unit === 'hours') {
            newDate.setHours(newDate.getHours() + amount, flooredMinutes, 0, 0)
        } else if (unit === 'minutes') {
            newDate.setHours(newDate.getHours(), flooredMinutes + amount, 0, 0)
        }
        setActiveHourIndex(newDate)
        if (!realtime) {
            updateChart(mappedDataRef.current, newDate)
        }
    }

    const handleToggle = () => {
        setIsAuto((prev) => !prev)
    }

    const handleSetPage = (page: "chart" | "table" | "table-ool", realtime: boolean) => {
        // set state
        setViewMode(page);
        setRealtime(realtime);

        // reset everything
        setSortedCols(null);
        setSortedColsType("ascending")
        setTableDataRealtimeFilter({})

        // update chart
        if (page == "chart") {
            if (realtime) {
                const map = splitDataBy10Minutes(tableDataRealtime)
                updateChartRealtime(map, activeHourIndex)
            } else {
                updateChart(mappedDataRef.current, activeHourIndex)
            }
        }
    }

    // excel
    const generateExcelRealtime = () => {
        if (tableDataRealtime.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = [
            "timestamp", "pressure", "pressure_min_warn",
            "pressure_max_warn", "pressure_min_alarm", "pressure_max_alarm"
        ]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableDataRealtime.length; i++) {
            values.push({
                timestamp: format(
                    typeof tableDataRealtime[i].timestamp === "string"
                        ? new Date(tableDataRealtime[i].timestamp)
                        : tableDataRealtime[i].timestamp,
                    "yyyy-MM-dd HH:mm:ss"
                ),
                pressure: `${tableDataRealtime[i].pressure}`,
                pressure_min_warn: `${tableDataRealtime[i].pressure_min_warn ?? ""}`,
                pressure_max_warn: `${tableDataRealtime[i].pressure_max_warn ?? ""}`,
                pressure_min_alarm: `${tableDataRealtime[i].pressure_min_alarm ?? ""}`,
                pressure_max_alarm: `${tableDataRealtime[i].pressure_max_alarm ?? ""}`,
            })
        }

        ExcelUtils.export(`Pressure Data Realtime`, column, values)
    }
    const generateExcel = () => {
        if (tableData.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = [
            "timestamp", "pressure", "pressure_min_warn",
            "pressure_max_warn", "pressure_min_alarm", "pressure_max_alarm"
        ]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableData.length; i++) {
            values.push({
                timestamp: format(
                    typeof tableData[i].timestamp === "string"
                        ? new Date(tableData[i].timestamp)
                        : tableData[i].timestamp,
                    "yyyy-MM-dd HH:mm:ss"
                ),
                pressure: `${tableData[i].pressure}`,
                pressure_min_warn: `${tableData[i].pressure_min_warn ?? ""}`,
                pressure_max_warn: `${tableData[i].pressure_max_warn ?? ""}`,
                pressure_min_alarm: `${tableData[i].pressure_min_alarm ?? ""}`,
                pressure_max_alarm: `${tableData[i].pressure_max_alarm ?? ""}`,
            })
        }

        ExcelUtils.export(`Pressure Data`, column, values)
    }

    useEffect(() => {
        if (realtime) {
            setHandleGenerateExcel(() => generateExcelRealtime)
        } else {
            setHandleGenerateExcel(() => generateExcel)
        }

        return () => {
            setHandleGenerateExcel(null)
        }
    }, [realtime, tableDataRealtime, tableData])

    return <>
        <div className={styles.cardBodyHeader}>

            {viewMode === 'chart' && realtime && (
                <>
                    <div className={styles.headerChart}>
                        <div style={{ gridColumn: '1 / span 3' }}>{formatDate(activeHourIndex, "dd MMM yyyy HH:mm")}</div>
                    </div>
                    <div className={styles.bodyChart}>
                        <button className={styles.buttonChart1} style={{ borderRadius: '12px 0 0 12px' }} onClick={() => {
                            handleChangeActiveHourIndex(-1, "hours")
                        }}><FaAngleDoubleLeft /></button>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(-10, "minutes")
                        }}><FaAngleLeft /></button>
                        <div className={styles.wrapperChart}>
                            <Line data={chartDataRealtime} options={chartOptionsRealtime} plugins={[statusAreaRealtime]} />
                        </div>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(10, "minutes")
                        }}><FaAngleRight /></button>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0 12px 12px 0' }} onClick={() => {
                            handleChangeActiveHourIndex(1, "hours")
                        }}><FaAngleDoubleRight /></button>
                    </div>
                </>
            )}
            {viewMode === 'table' && realtime && (
                <>
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    <th>
                                        {headerTableRealtime("timestamp", "Waktu")}
                                        {filterTableRealtime("timestamp", "Waktu")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("pressure", "Pressure")}
                                        {filterTableRealtime("pressure", "Pressure")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("pressure_max_alarm", "Pressure Max Alarm")}
                                        {filterTableRealtime("pressure_max_alarm", "Pressure Max Alarm")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("pressure_max_warn", "Pressure Max Warn")}
                                        {filterTableRealtime("pressure_max_warn", "Pressure Max Warn")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("pressure_min_alarm", "Pressure Min Alarm")}
                                        {filterTableRealtime("pressure_min_alarm", "Pressure Min Alarm")}
                                    </th>
                                    <th>
                                        {headerTableRealtime("pressure_min_warn", "Pressure Min Warn")}
                                        {filterTableRealtime("pressure_min_warn", "Pressure Min Warn")}
                                    </th>
                                </tr>
                            </thead>
                            {!filterUtils.FastIsEmpty(tableDataRealtime)
                                ? <tbody>
                                    <TableObserved
                                        tableData={tableDataRealtime}
                                        rowFunction={pressureDataRows}
                                        rowsCount={250}
                                        rowsIncrement={50}
                                    />
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>
                </>
            )}

            {viewMode === 'chart' && !realtime && (
                <>
                    <div className={styles.headerChart}>
                        <div style={{ gridColumn: '1 / span 3' }}>{formatDate(activeHourIndex, "dd MMM yyyy HH:mm")}</div>
                    </div>
                    <div className={styles.bodyChart}>
                        <button className={styles.buttonChart1} style={{ borderRadius: '12px 0 0 12px' }} onClick={() => {
                            handleChangeActiveHourIndex(-1, "hours")
                        }}><FaAngleDoubleLeft /></button>
                        <button className={styles.buttonChart1} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(-10, "minutes")
                        }}><FaAngleLeft /></button>
                        <div className={styles.wrapperChart}>
                            <Line data={chartData} options={chartOptions} plugins={[statusArea]} />
                        </div>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0' }} onClick={() => {
                            handleChangeActiveHourIndex(10, "minutes")
                        }}><FaAngleRight /></button>
                        <button className={styles.buttonChart2} style={{ borderRadius: '0 12px 12px 0' }} onClick={() => {
                            handleChangeActiveHourIndex(1, "hours")
                        }}><FaAngleDoubleRight /></button>
                    </div>
                </>
            )}
            {viewMode === 'table' && !realtime && (
                <>
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    <th>
                                        {headerTable("timestamp", "Waktu")}
                                        {filterTable("timestamp", "Waktu")}
                                    </th>
                                    <th>
                                        {headerTable("pressure", "Pressure")}
                                        {filterTable("pressure", "Pressure")}
                                    </th>
                                    <th>
                                        {headerTable("pressure_max_alarm", "Pressure Max Alarm")}
                                        {filterTable("pressure_max_alarm", "Pressure Max Alarm")}
                                    </th>
                                    <th>
                                        {headerTable("pressure_max_warn", "Pressure Max Warn")}
                                        {filterTable("pressure_max_warn", "Pressure Max Warn")}
                                    </th>
                                    <th>
                                        {headerTable("pressure_min_alarm", "Pressure Min Alarm")}
                                        {filterTable("pressure_min_alarm", "Pressure Min Alarm")}
                                    </th>
                                    <th>
                                        {headerTable("pressure_min_warn", "Pressure Min Warn")}
                                        {filterTable("pressure_min_warn", "Pressure Min Warn")}
                                    </th>
                                </tr>
                            </thead>
                            {!filterUtils.FastIsEmpty(tableData)
                                ? <tbody>
                                    <TableObserved
                                        tableData={tableData}
                                        rowFunction={pressureDataRows}
                                        rowsCount={250}
                                        rowsIncrement={50}
                                    />
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>
                </>
            )}

        </div>

        <div className={styles.cardBodyFooter}>
            <div className={styles.footerLeft}>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'chart' && realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('chart', true) }}>
                    <GrLineChart />
                    <span className={styles.tooltipText}>Realtime Chart</span>
                </button>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'table' && realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('table', true) }}>
                    <TbTable />
                    <span className={styles.tooltipText}>Realtime Table</span>
                </button>
            </div>
            <div className={styles.footerMid}>
                {viewMode === 'chart' && realtime && (
                    <div className={styles.switchGroup}>
                        <label htmlFor="auto">Auto</label>
                        <label className={styles.switch}>
                            <input type="checkbox" id="auto" checked={isAuto} onChange={handleToggle} />
                            <span className={styles.slider}></span>
                        </label>
                    </div>
                )}
            </div>
            <div className={styles.footerRight}>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'chart' && !realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('chart', false) }}>
                    <FaChartLine />
                    <span className={styles.tooltipText}>Chart</span>
                </button>
                <button
                    className={`${styles.buttonFooter} ${viewMode === 'table' && !realtime ? styles.active : ''}`}
                    onClick={() => { handleSetPage('table', false) }}>
                    <FaTable />
                    <span className={styles.tooltipText}>Table</span>
                </button>
            </div>
        </div>
    </>
}

export default PressurePage
